var LEAGUE_LOGO_FILE_MAX_BYTES = 5 * 1024 * 1024;
function resizeLogoFile(file, { maxPx = 128, quality = 0.82, maxBytes = 48e3, maxFileBytes = TEAM_LOGO_FILE_MAX_BYTES } = {}) {
  return new Promise((resolve, reject) => {
    if (!file?.type?.startsWith("image/")) {
      reject(new Error("Selecciona una imagen (JPG, PNG o WebP)"));
      return;
    }
    if (file.size > maxFileBytes) {
      const mb = maxFileBytes / (1024 * 1024);
      reject(new Error(`La imagen no puede superar ${mb} MB`));
      return;
    }
    const url = URL.createObjectURL(file);
    const img = new Image();
    img.onload = () => {
      URL.revokeObjectURL(url);
      const scale = Math.min(1, maxPx / Math.max(img.width, img.height));
      const w = Math.max(1, Math.round(img.width * scale));
      const h = Math.max(1, Math.round(img.height * scale));
      const canvas = document.createElement("canvas");
      canvas.width = w;
      canvas.height = h;
      const ctx = canvas.getContext("2d");
      const hasAlpha = file.type === "image/png" || file.type === "image/webp";
      if (hasAlpha) {
        ctx.fillStyle = "#000000";
        ctx.fillRect(0, 0, w, h);
      }
      ctx.drawImage(img, 0, 0, w, h);
      let q = quality;
      let dataUrl = canvas.toDataURL("image/jpeg", q);
      while (dataUrl.length > maxBytes * 1.37 && q > 0.45) {
        q -= 0.08;
        dataUrl = canvas.toDataURL("image/jpeg", q);
      }
      if (dataUrl.length > maxBytes * 1.37) {
        reject(new Error("Imagen demasiado grande; prueba otra m\xE1s simple"));
        return;
      }
      resolve(dataUrl);
    };
    img.onerror = () => {
      URL.revokeObjectURL(url);
      reject(new Error("No se pudo leer la imagen"));
    };
    img.src = url;
  });
}
